  "title": "CLI Arg Length Mitigation",
  "rules": [
    "When constructing commands on Windows, avoid long inline arguments.",
    "Prefer writing large inputs to temp files and pass file paths instead of raw text.",
    "If a command needs long JSON, write to a file and reference it with @file or --input-file flags when supported."
  ]
}
